def _provisional_visual_class(features: dict) -> tuple[str, str, float]:
    """
    Returns (visual_class_provisional, confidence, score_provisional).
    All thresholds are provisional starting points for calibration, not proven constants.
    """
    emb_max = features["embedded_image_bbox_area_ratio_max"]
    draw = features["drawing_density_proxy"]
    rendered = features.get("rendered_scan_signal")

    # embedded_image dominant
    if emb_max > 0.6:
        return "embedded_image_dominant", _confidence(emb_max, 0.6, 0.8), _score(emb_max, 0.7)

    # vector visual dominant — no embedded image, high drawing density
    elif draw > 0.3 and emb_max < 0.05:
        return "vector_visual_dominant", _confidence(draw, 0.3, 0.5), _score(draw, 0.4)

    # scan/raster dominant — near-blank native text, high rendered scan signal
    elif rendered is not None and rendered > 0.7 and emb_max < 0.05 and draw < 0.1:
        return "scan_raster_dominant", _confidence(rendered, 0.7, 0.85), _score(rendered, 0.75)

    # mixed — significant embedded image OR significant drawing
    elif emb_max > 0.1 or draw > 0.1:
        # Correction 3 applied: confidence based on dominant triggering feature, not min()
        dominant = max(emb_max, draw)
        return "mixed_visual_text", _confidence(dominant, 0.1, 0.25), _score(dominant, 0.2)

    # minor visual noise
    elif emb_max > 0.01 or draw > 0.01:
        return "minor_visual_noise", "low", 0.05

    # text dominant
    else:
        return "text_dominant", "high", 0.0


def _confidence(value: float, near: float, far: float) -> str:
    """Provisional confidence based on margin to threshold boundary."""
    if value >= far:
        return "high"
    elif value >= (near + far) / 2:
        return "medium"
    else:
        return "low"


def _score(value: float, typical: float) -> float:
    """Provisional composite score for exploratory ranking."""
    return round(min(1.0, value / typical), 4)
